 * Generate a unique job ID
 */
function generatePrefixedId(prefix: string, length = 8): string {
  const chars = 'REDACTED';
  let id = '';
  for (let i = 0; i < length; i++) {
    id += chars[Math.floor(Math.random() * chars.length)];
  }
  return `${prefix}_${id}`;
}

